/** Coordinates of a live cell as [x, y]. */
export type Cell = [number, number];

const MIN_LIVE_CELLS_TO_SURVIVE = 4;

export function nextGeneration(liveCells: Cell[]): Cell[] {
  if (liveCells.length < MIN_LIVE_CELLS_TO_SURVIVE) return [];
  return liveCells;
}
